#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, X;
        scanf("%lld %lld", &N, &X);
        printf("%lld\n", N - X);
    }
    return 0;
}

